Please review this Go code from our internal fraud detection service at Cyberix Labs. Focus on concurrency bugs, error handling, and performance issues.

```go
package fraudengine

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/cyberix-labs/platform/pkg/cyberixdb"
	"github.com/cyberix-labs/platform/pkg/cyberixmetrics"
	"github.com/cyberix-labs/platform/pkg/cyberixqueue"
)

type CyberixFraudScore struct {
	TransactionID string
	RiskLevel     CyberixRiskLevel
	Score         float64
	Rules         []CyberixRuleMatch
	ComputedAt    time.Time
}

type CyberixRiskLevel int

const (
	CyberixRiskLow    CyberixRiskLevel = iota
	CyberixRiskMedium
	CyberixRiskHigh
	CyberixRiskCritical
)

type CyberixFraudEngine struct {
	db       *cyberixdb.Client
	queue    *cyberixqueue.Publisher
	metrics  *cyberixmetrics.Collector
	rules    []CyberixFraudRule
	cache    map[string]*CyberixFraudScore
	cacheMu  sync.Mutex
}

type CyberixFraudRule interface {
	Evaluate(ctx context.Context, txn *CyberixTransaction) (float64, error)
	Name() string
	Weight() float64
}

type CyberixTransaction struct {
	ID              string
	Amount          float64
	Currency        string
	MerchantID      string
	CardFingerprint string
	IPAddress       string
	DeviceID        string
	UserID          string
	Timestamp       time.Time
	Metadata        map[string]interface{}
}

func NewCyberixFraudEngine(db *cyberixdb.Client, queue *cyberixqueue.Publisher) *CyberixFraudEngine {
	return &CyberixFraudEngine{
		db:      db,
		queue:   queue,
		metrics: cyberixmetrics.Default(),
		cache:   make(map[string]*CyberixFraudScore),
	}
}

func (e *CyberixFraudEngine) ScoreTransaction(ctx context.Context, txn *CyberixTransaction) (*CyberixFraudScore, error) {
	// Check cache first
	e.cacheMu.Lock()
	if cached, ok := e.cache[txn.ID]; ok {
		e.cacheMu.Unlock()
		return cached, nil
	}
	e.cacheMu.Unlock()

	var (
		totalScore float64
		totalWeight float64
		matches    []CyberixRuleMatch
		errs       []error
	)

	// Run all rules in parallel
	var wg sync.WaitGroup
	for _, rule := range e.rules {
		wg.Add(1)
		go func(r CyberixFraudRule) {
			defer wg.Done()
			score, err := r.Evaluate(ctx, txn)
			if err != nil {
				errs = append(errs, fmt.Errorf("rule %s failed: %w", r.Name(), err))
				return
			}
			totalScore += score * r.Weight()
			totalWeight += r.Weight()
			if score > 0.5 {
				matches = append(matches, CyberixRuleMatch{Rule: r.Name(), Score: score})
			}
		}(rule)
	}
	wg.Wait()

	normalizedScore := totalScore / totalWeight

	result := &CyberixFraudScore{
		TransactionID: txn.ID,
		RiskLevel:     e.classifyRisk(normalizedScore),
		Score:         normalizedScore,
		Rules:         matches,
		ComputedAt:    time.Now(),
	}

	// Cache result
	e.cacheMu.Lock()
	e.cache[txn.ID] = result
	e.cacheMu.Unlock()

	// Persist and publish async
	go e.persistScore(result)
	go e.queue.Publish("cyberix.fraud.scored", result)

	return result, nil
}

func (e *CyberixFraudEngine) classifyRisk(score float64) CyberixRiskLevel {
	switch {
	case score >= 0.9:
		return CyberixRiskCritical
	case score >= 0.7:
		return CyberixRiskHigh
	case score >= 0.4:
		return CyberixRiskMedium
	default:
		return CyberixRiskLow
	}
}

func (e *CyberixFraudEngine) persistScore(score *CyberixFraudScore) {
	e.db.Insert("cyberix_fraud_scores", score)
}

type CyberixRuleMatch struct {
	Rule  string
	Score float64
}
